"""Key management, password hashing, and field-level encryption.

We prefer SQLCipher for at-rest encryption when available; otherwise we fall
back to per-field AES-GCM (via `cryptography`) and an unencrypted SQLite file.
A friendly placeholder XOR cipher is used only when neither library is present
so the application remains runnable in restricted environments — this is
clearly NOT secure and emits a startup warning.
"""
from __future__ import annotations
import hashlib
import hmac
import os
import secrets
from base64 import b64encode, b64decode
from pathlib import Path

from . import config

try:
    from cryptography.hazmat.primitives.ciphers.aead import AESGCM
    HAVE_AESGCM = True
except Exception:  # pragma: no cover - cryptography not installed
    HAVE_AESGCM = False

# Emit a one-shot runtime warning when AES-GCM is unavailable. Production
# deployments MUST install `cryptography`; the XOR fallback exists only so
# the app can still boot for documentation/demo purposes.
if not HAVE_AESGCM:
    import logging as _logging
    import warnings as _warnings
    _msg = ("CRHGC: 'cryptography' library is missing — falling back to an "
            "INSECURE XOR cipher for sensitive fields. Install the "
            "`cryptography` package before storing real data.")
    _warnings.warn(_msg, RuntimeWarning, stacklevel=2)
    try:
        _logging.getLogger("crhgc.crypto").warning(_msg)
    except Exception:
        pass


# ---- Key file ------------------------------------------------------------

def load_or_create_key() -> bytes:
    p: Path = config.key_path()
    if p.exists():
        data = p.read_bytes()
        if len(data) >= 32:
            return data[:32]
    key = secrets.token_bytes(32)
    p.write_bytes(key)
    try:
        os.chmod(p, 0o600)
    except OSError:
        pass
    return key


# ---- Password hashing ----------------------------------------------------

def hash_password(password: str, salt: bytes | None = None) -> tuple[bytes, bytes]:
    if salt is None:
        salt = secrets.token_bytes(16)
    h = hashlib.pbkdf2_hmac("sha256", password.encode("utf-8"), salt,
                            config.PBKDF2_ITERATIONS)
    return h, salt


def verify_password(password: str, expected_hash: bytes, salt: bytes) -> bool:
    h, _ = hash_password(password, salt)
    return hmac.compare_digest(h, expected_hash)


# ---- Field encryption ----------------------------------------------------

_KEY: bytes | None = None


def _key() -> bytes:
    global _KEY
    if _KEY is None:
        _KEY = load_or_create_key()
    return _KEY


def encrypt_field(plain: str | None) -> str | None:
    """Encrypt a field value. Returns base64 string, or None for None input."""
    if plain is None or plain == "":
        return plain
    raw = plain.encode("utf-8")
    if HAVE_AESGCM:
        nonce = secrets.token_bytes(12)
        ct = AESGCM(_key()).encrypt(nonce, raw, None)
        return "v1:" + b64encode(nonce + ct).decode("ascii")
    # Insecure fallback (XOR with key stream) — flagged as v0.
    k = _key()
    out = bytes(b ^ k[i % len(k)] for i, b in enumerate(raw))
    return "v0:" + b64encode(out).decode("ascii")


def decrypt_field(token: str | None) -> str | None:
    if token is None or token == "":
        return token
    try:
        if token.startswith("v1:") and HAVE_AESGCM:
            data = b64decode(token[3:])
            nonce, ct = data[:12], data[12:]
            return AESGCM(_key()).decrypt(nonce, ct, None).decode("utf-8")
        if token.startswith("v0:"):
            data = b64decode(token[3:])
            k = _key()
            return bytes(b ^ k[i % len(k)] for i, b in enumerate(data)).decode("utf-8")
        # No prefix — assume it's stored cleartext (legacy/test fixture).
        return token
    except Exception:
        return None


# ---- File-level envelope (database at-rest) ------------------------------

_ENC_MAGIC = b"CRHGC1\x00"  # 7-byte magic + version sentinel


def encrypt_bytes_at_rest(raw: bytes) -> bytes:
    """Envelope-encrypt a byte buffer for at-rest storage.

    Layout (AES-GCM): ``CRHGC1\\x00 || nonce(12) || aesgcm(plain)``.
    Layout (XOR fallback): ``CRHGC0\\x00 || xor(plain)``.

    Pure in-memory transform — used by the in-memory SQLite path so the
    plaintext database never has to touch disk.
    """
    if HAVE_AESGCM:
        nonce = secrets.token_bytes(12)
        ct = AESGCM(_key()).encrypt(nonce, raw, None)
        return _ENC_MAGIC + nonce + ct
    k = _key()
    return b"CRHGC0\x00" + bytes(b ^ k[i % len(k)] for i, b in enumerate(raw))


def decrypt_bytes_at_rest(blob: bytes) -> bytes:
    """Reverse of ``encrypt_bytes_at_rest``. Returns plaintext bytes."""
    if blob.startswith(_ENC_MAGIC) and HAVE_AESGCM:
        nonce, ct = blob[7:19], blob[19:]
        return AESGCM(_key()).decrypt(nonce, ct, None)
    if blob.startswith(b"CRHGC0\x00"):
        k = _key()
        body = blob[7:]
        return bytes(b ^ k[i % len(k)] for i, b in enumerate(body))
    # Unknown / legacy plaintext — return unchanged so upgrades from
    # earlier versions don't lose data.
    return blob


def encrypt_file_at_rest(plain_path: Path, encrypted_path: Path) -> None:
    """Envelope-encrypt a file (e.g., the SQLite DB) for at-rest storage.

    Plaintext input is *not* removed by this function — callers decide
    whether to ``unlink()`` it after the encrypted blob is durably written.
    """
    encrypted_path.write_bytes(encrypt_bytes_at_rest(plain_path.read_bytes()))
    try:
        os.chmod(encrypted_path, 0o600)
    except OSError:
        pass


def decrypt_file_at_rest(encrypted_path: Path, plain_path: Path) -> None:
    """Reverse of ``encrypt_file_at_rest``. Writes plaintext to disk."""
    plain_path.write_bytes(decrypt_bytes_at_rest(encrypted_path.read_bytes()))
    try:
        os.chmod(plain_path, 0o600)
    except OSError:
        pass


# ---- Field masking -------------------------------------------------------

def mask_email(value: str | None) -> str:
    if not value:
        return ""
    if "@" not in value:
        return "***"
    local, domain = value.split("@", 1)
    return (local[:1] + "***@" + domain) if local else "***@" + domain


def mask_phone(value: str | None) -> str:
    if not value:
        return ""
    digits = [c for c in value if c.isdigit()]
    if len(digits) < 4:
        return "***"
    return "(***) ***-" + "".join(digits[-4:])


def mask_ssn_last4(value: str | None) -> str:
    if not value:
        return ""
    digits = [c for c in value if c.isdigit()]
    return "***-**-" + "".join(digits[-4:]) if digits else "***"

"""Append-only, hash-chained audit log."""
from __future__ import annotations
import hashlib
import json
from dataclasses import dataclass
from typing import Any

from . import db


def _canonical(payload: dict[str, Any]) -> str:
    return json.dumps(payload, sort_keys=True, separators=(",", ":"), default=str)


def record(actor_id: int | None, entity_type: str, entity_id: str | int,
           action: str, payload: dict[str, Any]) -> str:
    conn = db.get_connection()
    row = conn.execute(
        "SELECT this_hash FROM audit_log ORDER BY id DESC LIMIT 1"
    ).fetchone()
    prev_hash = row["this_hash"] if row else ""
    canonical = _canonical(payload)
    h = hashlib.sha256((prev_hash + canonical).encode("utf-8")).hexdigest()
    conn.execute(
        """INSERT INTO audit_log
           (actor_id, entity_type, entity_id, action, payload_json, prev_hash, this_hash)
           VALUES (?, ?, ?, ?, ?, ?, ?)""",
        (actor_id, entity_type, str(entity_id), action, canonical, prev_hash, h),
    )
    return h


@dataclass
class ChainVerification:
    ok: bool
    checked: int
    first_break_id: int | None = None


def verify_chain() -> ChainVerification:
    conn = db.get_connection()
    rows = conn.execute(
        "SELECT id, payload_json, prev_hash, this_hash FROM audit_log ORDER BY id"
    ).fetchall()
    expected_prev = ""
    for r in rows:
        if r["prev_hash"] != expected_prev:
            return ChainVerification(False, len(rows), r["id"])
        recomputed = hashlib.sha256(
            (expected_prev + r["payload_json"]).encode("utf-8")
        ).hexdigest()
        if recomputed != r["this_hash"]:
            return ChainVerification(False, len(rows), r["id"])
        expected_prev = r["this_hash"]
    return ChainVerification(True, len(rows))


def tail(limit: int = 100) -> list[dict[str, Any]]:
    conn = db.get_connection()
    rows = conn.execute(
        "SELECT id, ts, actor_id, entity_type, entity_id, action FROM audit_log "
        "ORDER BY id DESC LIMIT ?", (limit,)
    ).fetchall()
    return [dict(r) for r in rows]

"""Permission helpers and decorators."""
from __future__ import annotations
from dataclasses import dataclass, field
from datetime import datetime
from functools import wraps
from typing import Iterable


@dataclass
class Session:
    user_id: int
    username: str
    full_name: str
    roles: set[str] = field(default_factory=set)
    permissions: set[str] = field(default_factory=set)
    mask_unlock_until: datetime | None = None

    def has(self, code: str) -> bool:
        return code in self.permissions

    def has_any(self, codes: Iterable[str]) -> bool:
        return any(c in self.permissions for c in codes)

    def mask_unlocked(self) -> bool:
        return (self.mask_unlock_until is not None
                and self.mask_unlock_until > datetime.utcnow())


class PermissionDenied(Exception):
    def __init__(self, code: str):
        super().__init__(f"Permission denied: {code}")
        self.code = code


def requires(*codes: str):
    """Decorator: enforce that the first arg (session) holds all listed perms."""
    def deco(fn):
        @wraps(fn)
        def wrapped(self, session: Session, *args, **kw):
            for c in codes:
                if not session.has(c):
                    raise PermissionDenied(c)
            return fn(self, session, *args, **kw)
        return wrapped
    return deco

"""Application settings & synonym sets."""
from __future__ import annotations

from .. import audit, db
from ..permissions import Session, requires


class SettingsService:

    def get(self, key: str) -> str | None:
        conn = db.get_connection()
        r = conn.execute("SELECT value FROM settings WHERE key=?", (key,)).fetchone()
        return r["value"] if r else None

    @requires("system.admin")
    def set(self, session: Session, key: str, value: str) -> None:
        with db.transaction() as conn:
            conn.execute(
                "INSERT INTO settings(key, value) VALUES(?, ?) "
                "ON CONFLICT(key) DO UPDATE SET value=excluded.value", (key, value))
        audit.record(session.user_id, "settings", key, "set", {"value": value})

    def list_synonyms(self) -> list[dict]:
        conn = db.get_connection()
        return [dict(r) for r in conn.execute(
            "SELECT id, term, alt_term FROM synonyms ORDER BY term")]

    @requires("system.admin")
    def add_synonym(self, session: Session, term: str, alt: str) -> int:
        with db.transaction() as conn:
            cur = conn.execute(
                "INSERT INTO synonyms(term, alt_term) VALUES(?, ?) "
                "ON CONFLICT DO NOTHING", (term.lower(), alt.lower()))
        audit.record(session.user_id, "synonym", f"{term}->{alt}", "add", {})
        return cur.lastrowid

    @requires("system.admin")
    def remove_synonym(self, session: Session, syn_id: int) -> None:
        with db.transaction() as conn:
            conn.execute("DELETE FROM synonyms WHERE id=?", (syn_id,))
        audit.record(session.user_id, "synonym", syn_id, "remove", {})

"""Object-level authorization checks: student writes require permission."""
from __future__ import annotations
try:
    import pytest  # type: ignore
except ImportError:  # pragma: no cover
    class _Pytest:
        @staticmethod
        def raises(exc):
            class _Ctx:
                def __enter__(self_inner):
                    return self_inner
                def __exit__(self_inner, et, ev, tb):
                    if et is None:
                        raise AssertionError(f"expected {exc.__name__}")
                    return issubclass(et, exc)
            return _Ctx()
    pytest = _Pytest()  # type: ignore

from backend.models import StudentDTO
from backend.permissions import PermissionDenied, Session


def test_student_create_denied_without_permission(container, admin_session):
    # A bare session with no permissions should be rejected.
    bare = Session(user_id=admin_session.user_id, username="x", full_name="X")
    with pytest.raises(PermissionDenied):
        container.students.create(bare, StudentDTO(student_id="X1",
                                                   full_name="X"))


def test_student_update_denied_without_permission(container, admin_session):
    s = container.students.create(admin_session,
                                  StudentDTO(student_id="X2", full_name="Y"))
    bare = Session(user_id=admin_session.user_id, username="x", full_name="X")
    with pytest.raises(PermissionDenied):
        container.students.update(bare, s.id,
                                  StudentDTO(student_id="X2", full_name="Z"))


def test_student_import_denied_without_permission(container, admin_session,
                                                  tmp_path):
    csv_path = tmp_path / "in.csv"
    csv_path.write_text("student_id,full_name,college,class_year,email,phone,housing_status\n"
                        "S99,Foo,LA,2026,,,pending\n")
    bare = Session(user_id=admin_session.user_id, username="x", full_name="X")
    with pytest.raises(PermissionDenied):
        container.students.import_file(bare, csv_path)


def test_admin_can_create(container, admin_session):
    s = container.students.create(admin_session,
                                  StudentDTO(student_id="X3", full_name="OK"))
    assert s.id > 0


def test_coordinator_can_create(container, coordinator_session):
    s = container.students.create(coordinator_session,
                                  StudentDTO(student_id="X4", full_name="OK"))
    assert s.id > 0

